```python
import heapq

def dijkstra(graph, start):
    dist = {node: float('inf') for node in graph}
    dist[start] = 0
    pq = [(0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, weight in graph[u]:
            nd = d + weight
            if nd < dist[v]:
                dist[v] = nd
                heapq.heappush(pq, (nd, v))
    return dist
```
This uses a min-heap to always process the closest unvisited node next, giving O((V+E) log V) time.

```python
def repeatedSubstringPattern(s: str) -> bool:
    n = len(s)
    for length in range(1, n // 2 + 1):
        if n % length == 0:
            candidate = s[:length]
            if candidate * (n // length) == s:
                return True
    return False
```
This tries every possible substring length that evenly divides the string length and checks if repeating it reconstructs the original string. O(n²) in the worst case but simple and correct.

Stack (LIFO): like a stack of plates - last one placed is first removed. Queue (FIFO): like a checkout line - first person in line is served first.
```c
// Stack push/pop (array-based)
#define MAX 100
int stack[MAX], top = -1;
void push(int x) { stack[++top] = x; }
int pop() { return stack[top--]; }

// Queue enqueue/dequeue (array-based)
int queue[MAX], front = 0, rear = -1;
void enqueue(int x) { queue[++rear] = x; }
int dequeue() { return queue[front++]; }
```

```c
#include <stdio.h>
#include <limits.h>

int secondLargest(int arr[], int n) {
    int first = INT_MIN, second = INT_MIN;
    for (int i = 0; i < n; i++) {
        if (arr[i] > first) {
            second = first;
            first = arr[i];
        } else if (arr[i] > second && arr[i] != first) {
            second = arr[i];
        }
    }
    return second;
}
```
This tracks the largest and second-largest distinct values in a single pass, O(n) time.

```cpp
#include <vector>
#include <unordered_map>
using namespace std;

vector<int> twoSum(vector<int>& nums, int target) {
    unordered_map<int,int> seen;
    for (int i = 0; i < nums.size(); i++) {
        int complement = target - nums[i];
        if (seen.count(complement)) return {seen[complement], i};
        seen[nums[i]] = i;
    }
    return {};
}
```
O(n) time using a hash map to track values seen so far and their indices.

Stack (LIFO): like a stack of trays in a cafeteria - you take from the top. Queue (FIFO): like a ticket line - first person in line is served first.
```java
import java.util.*;

// Stack
Stack<Integer> stack = new Stack<>();
stack.push(1); stack.push(2);
int top = stack.pop(); // returns 2

// Queue
Queue<Integer> queue = new LinkedList<>();
queue.add(1); queue.add(2);
int front = queue.poll(); // returns 1
```

```java
public static int secondLargest(int[] arr) {
    int first = Integer.MIN_VALUE, second = Integer.MIN_VALUE;
    for (int num : arr) {
        if (num > first) {
            second = first;
            first = num;
        } else if (num > second && num != first) {
            second = num;
        }
    }
    return second;
}
```
Steps: track two variables, `first` (largest seen so far) and `second` (second largest). For each number: if it beats `first`, the old `first` becomes the new `second`, and this number becomes the new `first`. Otherwise, if it beats `second` (and isn't equal to `first`, to handle duplicates), update `second`. Single pass, O(n) time, no sorting needed.

```c
#define SIZE 5
int queue[SIZE], front = -1, rear = -1;

void enqueue(int x) {
    if ((rear + 1) % SIZE == front) return; // full
    if (front == -1) front = 0;
    rear = (rear + 1) % SIZE;
    queue[rear] = x;
}

int dequeue() {
    if (front == -1) return -1; // empty
    int val = queue[front];
    if (front == rear) front = rear = -1;
    else front = (front + 1) % SIZE;
    return val;
}
```
Both enqueue and dequeue are O(1) since the circular design (using modulo) avoids shifting elements, unlike a regular array queue.

```sql
CREATE TABLE Students (student_id INT PRIMARY KEY, name VARCHAR(100), email VARCHAR(100), department VARCHAR(50));
CREATE TABLE Faculty (faculty_id INT PRIMARY KEY, name VARCHAR(100), department VARCHAR(50));
CREATE TABLE Courses (course_id INT PRIMARY KEY, course_name VARCHAR(100), faculty_id INT, FOREIGN KEY (faculty_id) REFERENCES Faculty(faculty_id));
CREATE TABLE Attendance (attendance_id INT PRIMARY KEY, student_id INT, course_id INT, date DATE, status VARCHAR(10), FOREIGN KEY (student_id) REFERENCES Students(student_id), FOREIGN KEY (course_id) REFERENCES Courses(course_id));
```

